367	// TestHarborRunnerImageNoHostPython verifies scripts/benchmark/harbor-runner/Dockerfile
368	// does not rely on host Python site-packages and build.sh only uses files under
369	// scripts/benchmark/harbor-runner/ and scripts/benchmark/harbor_adapters/.
370	func TestHarborRunnerImageNoHostPython(t *testing.T) {
