377			t.Fatalf("Dockerfile not found: %v", err)
378		}
379	
380		dockerfileContent := string(dockerfileData)
381	
382		// Check that Dockerfile does not mount or copy host site-packages
383		hostPythonPatterns := []string{
384			"site-packages",
385			"/usr/local/lib/python",
386			"/usr/lib/python",
387		}
388	
389		for _, pattern := range hostPythonPatterns {
390			if strings.Contains(dockerfileContent, pattern) {
391				t.Errorf("Dockerfile contains reference to host Python: %s", pattern)
392			}
393		}
394	
395		// Check that Dockerfile doesn't do COPY from host Python locations
396		if strings.Contains(dockerfileContent, "COPY /") {
397			t.Errorf("Dockerfile uses absolute COPY paths which may reference host Python")
398		}
399	
400		// Verify build.sh only references appropriate paths
401		buildScriptData, err := os.ReadFile(buildScript)
402		if err != nil {
403			t.Fatalf("build.sh not found: %v", err)
404		}
