// TestBenchmarkRunnerEndToEnd drives a full cell with shell adapter + harbor executor.
// Skipped when docker is unavailable.
func TestBenchmarkRunnerEndToEnd(t *testing.T) {
	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	tmpDir := t.TempDir()
	tasksDir := filepath.Join(tmpDir, "tasks")
	outDir := filepath.Join(tmpDir, "out")

	if err := os.MkdirAll(tasksDir, 0755); err != nil {
		t.Fatalf("failed to create tasks dir: %v", err)
	}
	if err := os.MkdirAll(outDir, 0755); err != nil {
		t.Fatalf("failed to create output dir: %v", err)
	}

	cmd := exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--out", outDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"HARBOR_TASK_EXECUTOR_DRY_RUN=1",
		"BENCH_TASKS_DIR="+tasksDir,
		"BENCH_HARBOR_DIGEST_OVERRIDE=sha256:test-digest")

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Logf("stderr: %s", stderr.String())
		t.Fatalf("benchmark run failed: %v", err)
	}

	// Verify sweep.json was created
	sweepPath := filepath.Join(outDir, "sweep.json")
	if _, err := os.Stat(sweepPath); err != nil {
		t.Fatalf("sweep.json not created: %v", err)
	}

	// Verify cells were created with report.json
	cellsDir := filepath.Join(outDir, "cells")
	if _, err := os.Stat(cellsDir); err != nil {
		t.Fatalf("cells directory not created: %v", err)
	}

	// Count report.json files
	reportCount := 0
	filepath.Walk(cellsDir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.Name() == "report.json" {
			reportCount++
		}
		return nil
	})

	if reportCount == 0 {
		t.Fatalf("no report.json files created")
	}
	t.Logf("created %d cells", reportCount)
}

// TestBenchmarkRunnerResumeSkipsCompleted verifies resume-by-report.json and --force-rerun.
func TestBenchmarkRunnerResumeSkipsCompleted(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	tmpDir := t.TempDir()
	tasksDir := filepath.Join(tmpDir, "tasks")
	outDir := filepath.Join(tmpDir, "out")

	if err := os.MkdirAll(tasksDir, 0755); err != nil {
		t.Fatalf("failed to create tasks dir: %v", err)
	}
	if err := os.MkdirAll(outDir, 0755); err != nil {
		t.Fatalf("failed to create output dir: %v", err)
	}

	// First run
	cmd := exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--out", outDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"HARBOR_TASK_EXECUTOR_DRY_RUN=1",
		"BENCH_TASKS_DIR="+tasksDir,
		"BENCH_HARBOR_DIGEST_OVERRIDE=sha256:test-digest")

	if err := cmd.Run(); err != nil {
		t.Fatalf("first benchmark run failed: %v", err)
	}

	// Count cells after first run
	countCells := func() int {
		count := 0
		filepath.Walk(filepath.Join(outDir, "cells"), func(path string, info os.FileInfo, err error) error {
			if err != nil {
				return err
			}
			if info.Name() == "report.json" {
				count++
			}
			return nil
		})
		return count
	}

	firstCount := countCells()
	if firstCount == 0 {
		t.Fatalf("first run created no cells")
	}

	// Second run (resume, no --force-rerun) should skip
	cmd = exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--out", outDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"HARBOR_TASK_EXECUTOR_DRY_RUN=1",
		"BENCH_TASKS_DIR="+tasksDir,
		"BENCH_HARBOR_DIGEST_OVERRIDE=sha256:test-digest")

	if err := cmd.Run(); err != nil {
		t.Fatalf("second benchmark run failed: %v", err)
	}

	secondCount := countCells()
	if secondCount != firstCount {
		t.Errorf("resume should skip completed cells; got %d cells before and %d after", firstCount, secondCount)
	}
}

// TestBenchmarkRunnerRetryInvalid verifies --retry-invalid semantics.
func TestBenchmarkRunnerRetryInvalid(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	tmpDir := t.TempDir()
	tasksDir := filepath.Join(tmpDir, "tasks")
	outDir := filepath.Join(tmpDir, "out")

	if err := os.MkdirAll(tasksDir, 0755); err != nil {
		t.Fatalf("failed to create tasks dir: %v", err)
	}
	if err := os.MkdirAll(outDir, 0755); err != nil {
		t.Fatalf("failed to create output dir: %v", err)
	}

	// First run
	cmd := exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--out", outDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"HARBOR_TASK_EXECUTOR_DRY_RUN=1",
		"BENCH_TASKS_DIR="+tasksDir,
		"BENCH_HARBOR_DIGEST_OVERRIDE=sha256:test-digest")

	if err := cmd.Run(); err != nil {
		t.Fatalf("first benchmark run failed: %v", err)
	}

	// Mark first cell as invalid by finding and modifying report.json
	cellsDir := filepath.Join(outDir, "cells")
	var cellPath string
	filepath.Walk(cellsDir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.Name() == "report.json" && cellPath == "" {
			cellPath = path
		}
		return nil
	})

	if cellPath == "" {
		t.Fatalf("no report.json found to mark as invalid")
	}

	// Read, modify, and write back
	reportData, err := os.ReadFile(cellPath)
	if err != nil {
		t.Fatalf("failed to read report.json: %v", err)
	}

	var report map[string]interface{}
	if err := json.Unmarshal(reportData, &report); err != nil {
		t.Fatalf("report.json is not valid JSON: %v", err)
	}

	report["invalid_class"] = "setup_failure"
	report["final_status"] = "invalid"

	newReportData, err := json.Marshal(report)
	if err != nil {
		t.Fatalf("failed to marshal modified report: %v", err)
	}

	if err := os.WriteFile(cellPath, newReportData, 0644); err != nil {
		t.Fatalf("failed to write modified report.json: %v", err)
	}

	// Run with --retry-invalid
	cmd = exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--retry-invalid",
		"--out", outDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"HARBOR_TASK_EXECUTOR_DRY_RUN=1",
		"BENCH_TASKS_DIR="+tasksDir,
		"BENCH_HARBOR_DIGEST_OVERRIDE=sha256:test-digest")

	if err := cmd.Run(); err != nil {
		t.Fatalf("retry-invalid run failed: %v", err)
	}

	// Verify a new cell was created with attempt_of
	foundAttemptOf := false
	filepath.Walk(cellsDir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.Name() == "report.json" && path != cellPath {
			data, _ := os.ReadFile(path)
			var r map[string]interface{}
			if json.Unmarshal(data, &r) == nil {
				if _, hasAttemptOf := r["attempt_of"]; hasAttemptOf {
					foundAttemptOf = true
				}
			}
		}
		return nil
	})

	if !foundAttemptOf {
		t.Errorf("--retry-invalid did not create a new cell with attempt_of")
	}
}

