// TestBenchmarkRunnerSignalHandling verifies SIGTERM signal handling.
func TestBenchmarkRunnerSignalHandling(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	tmpDir := t.TempDir()
	tasksDir := filepath.Join(tmpDir, "tasks")
	outDir := filepath.Join(tmpDir, "out")

	for _, dir := range []string{tasksDir, outDir} {
		if err := os.MkdirAll(dir, 0755); err != nil {
			t.Fatalf("failed to create directory: %v", err)
		}
	}

	cmd := exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--out", outDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"HARBOR_TASK_EXECUTOR_DRY_RUN=1",
		"BENCH_TASKS_DIR="+tasksDir,
		"BENCH_HARBOR_DIGEST_OVERRIDE=sha256:test-digest")

	// Start the process
	if err := cmd.Start(); err != nil {
		t.Fatalf("failed to start benchmark: %v", err)
	}

	// Give it a moment to start processing
	time.Sleep(100 * time.Millisecond)

	// Send SIGTERM to stop gracefully
	cmd.Process.Signal(os.Interrupt)

	// Wait for completion with timeout
	done := make(chan error, 1)
	go func() {
		done <- cmd.Wait()
	}()

	select {
	case err := <-done:
		// Command should exit, either successfully or with signal indication
		if err != nil && err.Error() != "signal: interrupt" {
			t.Logf("benchmark exited with: %v (expected interrupt or nil)", err)
		}
	case <-time.After(10 * time.Second):
		cmd.Process.Kill()
		t.Fatalf("benchmark did not respond to SIGTERM within timeout")
	}

	t.Logf("signal handling test completed")
}

// TestBenchmarkRunnerPreflight verifies the preflight subcommand.
func TestBenchmarkRunnerPreflight(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	cmd := exec.Command(benchmarkScript, "preflight")
	cmd.Dir = benchDir

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()

	// Preflight can succeed or fail depending on environment; we just verify it runs
	// and produces output indicating what it checked
	output := stdout.String() + stderr.String()

	if !strings.Contains(output, "preflight") {
		t.Errorf("preflight output does not contain 'preflight': %s", output)
	}

	// Verify preflight checks for required tools
	requiredChecks := []string{"harbor-runner", "image-content-sha"}
	for _, check := range requiredChecks {
		if !strings.Contains(output, check) {
			t.Logf("preflight output missing mention of '%s': %s", check, output)
		}
	}

	t.Logf("preflight exited with code: %v", err)
}

